+
+        for mode in ["raw", "strict", "hardened"] {
+            let mode_row = baseline[mode].as_object().unwrap();
+            assert_eq!(
+                mode_row["capture_state"].as_str(),
+                Some("measured"),
+                "{symbol}.{mode} should be measured after memcmp/strcmp string bench ingestion"
